  \item \textbf{Notas:}
    \begin{itemize}
      \item Entender o uso da reta de tendência para previsão.
      \item Calcular equação da reta a partir dos pontos do gráfico.
      \item Realizar extrapolação para além dos dados apresentados.
    \end{itemize}
\end{itemize}

